from langchain.agents import tool

@tool
def calculator(expression: str) -> str:
    '''Evaluate a math expression.'''
    return str(eval(expression))

@tool
def get_weather(city: str) -> str:
    '''Get current weather for a city.'''
    return f'{city}: 28C, Sunny'

# Agent decides which tools to call
# Input: 'Temperature in Chennai in Fahrenheit?'
# Thought: I need weather first, then convert
# Action: get_weather('Chennai') => '28C, Sunny'
# Action: calculator('28*9/5+32') => '82.4'
# Answer: 'Chennai is 82.4F and Sunny'
